#!/usr/bin/env node
// Extract memory values from an ELF binary.
// Loads every PT_LOAD segment at base 0x400000 (matching the reference's
// virtual-address layout) and emits each 4-byte little-endian word as
// { "<address>": <int32 value> }.

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <binary>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// --- ELF header sanity check ---
if (buf.length < 64 ||
    buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const is64 = buf[4] === 2;          // EI_CLASS: 2 == ELFCLASS64
const little = buf[5] === 1;        // EI_DATA: 1 == little-endian

function rd(off, size) {
  // read unsigned integer of `size` bytes as a Number (safe up to 2^53)
  let v = 0;
  if (little) {
    for (let i = size - 1; i >= 0; i--) v = v * 256 + buf[off + i];
  } else {
    for (let i = 0; i < size; i++) v = v * 256 + buf[off + i];
  }
  return v;
}

const BASE = 0x400000; // reference load base (example key 4194304 == 0x400000)

let phoff, phentsize, phnum;
if (is64) {
  phoff = rd(0x20, 8);
  phentsize = rd(0x36, 2);
  phnum = rd(0x38, 2);
} else {
  phoff = rd(0x1c, 4);
  phentsize = rd(0x2a, 2);
  phnum = rd(0x28, 2);
}

const PT_LOAD = 1;
const out = {};

for (let i = 0; i < phnum; i++) {
  const ph = phoff + i * phentsize;
  const type = rd(ph, 4);
  if (type !== PT_LOAD) continue;

  let offset, vaddr, filesz;
  if (is64) {
    offset = rd(ph + 0x08, 8);
    vaddr = rd(ph + 0x10, 8);
    filesz = rd(ph + 0x20, 8);
  } else {
    offset = rd(ph + 0x04, 4);
    vaddr = rd(ph + 0x08, 4);
    filesz = rd(ph + 0x10, 4);
  }

  // Emit complete 4-byte words backed by file contents.
  const words = Math.floor(filesz / 4);
  for (let w = 0; w < words; w++) {
    const fo = offset + w * 4;
    if (fo + 4 > buf.length) break;
    const addr = BASE + vaddr + w * 4;
    out[addr] = buf.readUInt32LE(fo);
  }
}

process.stdout.write(JSON.stringify(out));

