cd /app && node extract.js /app/a.out > out.json && node -e '
const o=require("./out.json");
const k=Object.keys(o);
console.log("num entries:",k.length);
console.log("min addr:",Math.min(...k.map(Number)),"max addr:",Math.max(...k.map(Number)));
console.log("first key val:",o["4194304"], "hex", o["4194304"].toString(16));
console.log("sample:", JSON.stringify(Object.fromEntries(k.slice(0,4).map(x=>[x,o[x]]))));
'

