cd /app && ls -la; find / -name "*test*" -path "*app*" 2>/dev/null | head; echo "---run---"; node extract.js /app/a.out | node -e '
let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{
  const o=JSON.parse(d);
  const k=Object.keys(o);
  let ok=true;
  for(const key of k){
    if(!Number.isInteger(o[key])){ok=false;console.log("non-int",key);break;}
    if(o[key]<0||o[key]>0xffffffff){ok=false;console.log("range",key,o[key]);break;}
    if(Number(key)%4!==0){ok=false;console.log("unaligned",key);break;}
  }
  console.log("entries:",k.length,"all valid uint32 aligned:",ok);
  console.log("addr 0x400000 =",o["4194304"].toString(16),"(expect 464c457f ELF magic)");
});'

